def _hex_to_rgba(hex_color: str, alpha: float) -> str:
    """Convert a 6-digit hex colour to an rgba() string."""
    h = hex_color.lstrip("#")
    r, g, b = int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16)
    return f"rgba({r},{g},{b},{alpha})"
